$danawa$::jsonb
  ) AS seed(part_public_id TEXT, price INTEGER, collected_at TIMESTAMPTZ, raw_payload JSONB)
)
INSERT INTO price_snapshots (part_id, price, source, collected_at, raw_payload)
SELECT p.id,
       seed.price,
       'DANAWA_PRICE_TREND',
       seed.collected_at,
       seed.raw_payload
FROM trend_seed seed
JOIN parts p ON p.public_id = seed.part_public_id::uuid
ON CONFLICT (part_id, source, collected_at) WHERE source = 'DANAWA_PRICE_TREND'
DO UPDATE SET
  price = EXCLUDED.price,
  raw_payload = EXCLUDED.raw_payload;

